    unsigned int byte2 = (val >> 16) & 0xFF;
    unsigned int byte3 = (val >> 24) & 0xFF;
    printf("val    = 0x%08X\n", val);
    printf("byte0  = 0x%02X\n", byte0);
    printf("byte1  = 0x%02X\n", byte1);
    printf("byte2  = 0x%02X\n", byte2);
    printf("byte3  = 0x%02X\n", byte3);
    unsigned int nibble_lo = val & 0x0F;
    unsigned int nibble_hi = (val >> 4) & 0x0F;
    printf("lo nib = 0x%X\n", nibble_lo);
    printf("hi nib = 0x%X\n", nibble_hi);
    return 0;
}

