/* == EXEMPLE ================================================
 * Masquage: extraire des champs de bits
 * =========================================================== */
void example_mask(void) {
    unsigned int x = 0xABCD;
    printf("lo byte = 0x%02X\n", x & 0xFF);       /* 0xCD */
    printf("hi byte = 0x%02X\n", (x >> 8) & 0xFF); /* 0xAB */
}

/* == VOTRE EXERCICE =========================================
 * Extraire les 4 octets et 2 nibbles de 0xDEADBEEF
 * =========================================================== */

int main(void) {
    unsigned int val = 0xDEADBEEF;
    unsigned int byte0 = val & 0xFF;
    unsigned int byte1 = (val >> 8) & 0xFF;
    unsigned int byte2 = (val >> 16) & 0xFF;
    unsigned int byte3 = (val >> 24) & 0xFF;
    printf("val    = 0x%08X\n", val);
    printf("byte0  = 0x%02X\n", byte0);
    printf("byte1  = 0x%02X\n", byte1);
    printf("byte2  = 0x%02X\n", byte2);
    printf("byte3  = 0x%02X\n", byte3);
    /* TODO: nibbles */
    unsigned int nibble_lo = val & 0x0F;
    unsigned int nibble_hi = (val >> 4) & 0x0F;
    printf("lo nib = 0x%X\n", nibble_lo);
    printf("hi nib = 0x%X\n", nibble_hi);
    return 0;
}

